local CGameTimeTask = class("GameTimeTask", ITask)

function CGameTimeTask:onCreate()
    SkillManager:init()
    PayStore:init()
    GameStateManager:init()
    AreaManager:createArea()
end

function CGameTimeTask:onTick(ticks)
    --print("CGameTimeTask:onTick " .. ticks)

    GameStateManager:onTick(ticks)
    PlayerManager:onTick(ticks)
    SkillManager:onTick(ticks)
    TeamManager:tick(ticks)
    LSChampionShipWeb:tryUploadScore()
    JumpGameManager:onTick()

    --发送排行榜
    if ticks % (5 * GameMatch.tickPerSecond) == 0 then
        LSRankManager:senderAllPlayerRank()
    end

    local readyPlayerCount = PlayerManager:getReadyPlayerCount()
    local waitPlayerNum = ChampionShipConfig.waitPlayerNum or 2
    if ticks % (30 * GameMatch.tickPerSecond) == 0
            and GameStateManager:getGameState() < Define.GameStatus.WaitPlayerCountDown then
        MsgSender.sendMsg(IMessages:msgWaitPlayer())
        MsgSender.sendMsg(IMessages:msgGamePlayerNum(readyPlayerCount, waitPlayerNum))
    end
end

GameTimeTask = CGameTimeTask.new(1, GameMatch.tickInterval)

return GameTimeTask